from flask import Flask, request, jsonify
from flask_bcrypt import Bcrypt
import pyotp

app = Flask(__name__)
bcrypt = Bcrypt(app)

# Sample user database (replace with a proper database)
users = {
    "user1": {"password": bcrypt.generate_password_hash("password123").decode('utf-8'), "mfa_enabled": True, "mfa_secret": "JH4G5K6JHG"},
    "api_client": {"password": bcrypt.generate_password_hash("api_password").decode('utf-8'), "mfa_enabled": False}
}

@app.route('/api/login', methods=['POST'])
def login():
    username = request.json.get('username')
    password = request.json.get('password')

    if username not in users:
        return jsonify({"error": "Invalid username"}), 401

    user = users[username]
    if not bcrypt.check_password_hash(user['password'], password):
        return jsonify({"error": "Invalid password"}), 401

    # Check for MFA
    if user['mfa_enabled']:
        totp = pyotp.TOTP(user['mfa_secret']).now()
        otp_from_request = request.json.get('otp')
        if otp_from_request != totp:
            return jsonify({"error": "Invalid OTP"}), 401

    # Login successful, grant access
    return jsonify({"access_token": username}), 200

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    username = request.json.get('username')
    password = request.json.get('password')

    if username not in users:
        return jsonify({"error": "Invalid username"}), 401

    user = users[username]
    if not bcrypt.check_password_hash(user['password'], password):
        return jsonify({"error": "Invalid password"}), 401

    # Direct login skips MFA checks
    return jsonify({"access_token": username}), 200

if __name__ == '__main__':
    app.run(debug=True)